Here is a simple example of implementing JWT (JSON Web Tokens) authentication in a Node.js application using the `jsonwebtoken` package:

1. Install the necessary packages:
```bash
npm install jsonwebtoken express
```

2. Create a basic Node.js application with JWT authentication:

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');
const app = express();

// Secret key for signing tokens
const secretKey = 'your-secret-key';

// Middleware to check for JWT in request headers
function authenticateToken(req, res, next) {
    const authHeader = req.headers['authorization'];
    const token = authHeader && authHeader.split(' ')[1];

    if (token == null) {
        return res.sendStatus(401);
    }

    jwt.verify(token, secretKey, (err, user) => {
        if (err) {
            return res.sendStatus(403);
        }
        req.user = user;
        next();
    });
}

// Route protected by JWT
app.get('/protected', authenticateToken, (req, res) => {
    res.send({ message: 'Welcome to the protected route' });
});

// Route to generate JWT
app.post('/login', (req, res) => {
    const user = { id: 1, username: 'user' };
    const token = jwt.sign(user, secretKey, { expiresIn: '1h' });
    res.send({ token });
});

app.listen(3000, () => {
    console.log('Server is running on port 3000');
});
```

This example includes a simple server that listens on port 3000. It has two endpoints: one for generating a JWT token and another for a protected route that requires authentication. The `authenticateToken` middleware checks the token in the request headers and verifies it using the `jsonwebtoken` library.
